#[AsTransactionListener(events: ['LedgerImbalanceDetected'], queue: 'finance-critical', priority: 10)]
final class HaltNewTransactionsOnImbalance
{
    public function __invoke(LedgerImbalanceDetected $event): void
    {
        // Set tenant.transaction_halt_new = true. Every subsequent
        // TransactionRecorder::record() call refuses until an ops-authored fix lands.
    }
}

#[AsLedgerAccount(slug: 'cash', regulator_category: 'asset', enabled_by_default: true)]
final class CashAccount implements ILedgerAccount
{
    public function display_name(): string { return 'Cash'; }
}

#[AsTransactionKind(kind: 'invoice_payment', canonical_entries: [['debit' => 'cash', 'credit' => 'accounts_receivable']])]
final class InvoicePaymentKind implements ITransactionKindHandler
{
    public function buildLedgerEntries(TransactionData $data): array
    {
        return [
            new LedgerEntryData(account: 'cash', debit_cents: $data->amount_cents, credit_cents: 0),
            new LedgerEntryData(account: 'accounts_receivable', debit_cents: 0, credit_cents: $data->amount_cents),
        ];
    }
}
